export const getRegionLabel = (
  countryCode: string | undefined = ''
): string => {
  const code = countryCode?.toLowerCase();
  switch (code) {
    case 'us':
      return 'State';
    case 'ca':
      return 'Province';
    default:
      return 'State';
  }
};

export const getPostalCodeLabel = (
  countryCode: string | undefined = ''
): string => {
  const code = countryCode?.toLowerCase();
  switch (code) {
    case 'us':
      return 'ZIP';
    case 'ca':
      return 'Postal Code';
    default:
      return 'Postal Code';
  }
};
